# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import functions_framework
from google.cloud import storage, firestore, pubsub_v1
import base64
import json
import os

# Initialize Google Cloud clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Get Pub/Sub topic name from environment variable
# It's good practice to make this configurable
PUBSUB_TOPIC_NAME = os.environ.get('PUBSUB_TOPIC_NAME', 'my-processed-files-topic')
PROJECT_ID = os.environ.get('GOOGLE_CLOUD_PROJECT')

if not PROJECT_ID:
    raise ValueError("GOOGLE_CLOUD_PROJECT environment variable not set.")

PUBSUB_TOPIC_PATH = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC_NAME)

@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    """
    Responds to a Cloud Storage event, processes the file, writes metadata to Firestore,
    and publishes a message to Pub/Sub.
    Args:
        cloud_event (google.cloud.functions.CloudEvent): The Cloud Event object.
            This object contains information about the event, including `data` (the event payload)
            and `context` (event metadata).
    """
    data = cloud_event.data

    # Extract relevant information from the Cloud Storage event
    bucket_name = data['bucket']
    file_name = data['name']
    event_id = cloud_event['id']
    event_type = cloud_event['type']
    time_created = data['timeCreated']

    print(f"Processing file: {file_name} from bucket: {bucket_name}")
    print(f"Event ID: {event_id}, Event Type: {event_type}")

    try:
        # 1. Download and process the file content (example: read as text)
        bucket = storage_client.get_bucket(bucket_name)
        blob = bucket.blob(file_name)
        file_content = blob.download_as_text()
        content_length = len(file_content)
        first_100_chars = file_content[:100] if content_length > 0 else ""

        print(f"File '{file_name}' downloaded. Content length: {content_length} bytes.")
        print(f"First 100 characters: '{first_100_chars}...'")

        # 2. Write metadata and processing results to Firestore
        doc_ref = firestore_client.collection('processed_files').document(file_name.replace('.', '_'))
        firestore_data = {
            'bucket': bucket_name,
            'fileName': file_name,
            'gcsEventId': event_id,
            'timeCreatedGCS': time_created,
            'processedTime': firestore.SERVER_TIMESTAMP,
            'contentLength': content_length,
            'firstChars': first_100_chars,
            'status': 'processed_successfully'
        }
        doc_ref.set(firestore_data)
        print(f"Metadata for '{file_name}' written to Firestore document: {doc_ref.id}")

        # 3. Publish a message to Pub/Sub
        pubsub_message_data = {
            'fileName': file_name,
            'bucketName': bucket_name,
            'firestoreDocId': doc_ref.id,
            'status': 'success',
            'processedAt': firestore_data['processedTime'], # Will be SERVER_TIMESTAMP in Firestore
            'gcsEventId': event_id
        }
        
        # Pub/Sub messages must be bytes
        data_bytes = json.dumps(pubsub_message_data).encode('utf-8')
        
        future = publisher.publish(PUBSUB_TOPIC_PATH, data_bytes, file_name=file_name.encode('utf-8'))
        message_id = future.result()
        print(f"Message published to Pub/Sub topic '{PUBSUB_TOPIC_NAME}' with ID: {message_id}")

    except Exception as e:
        print(f"Error processing file {file_name}: {e}")
        # Optionally, publish an error message to Pub/Sub or log to another service
        error_message_data = {
            'fileName': file_name,
            'bucketName': bucket_name,
            'gcsEventId': event_id,
            'status': 'error',
            'errorMessage': str(e)
        }
        error_data_bytes = json.dumps(error_message_data).encode('utf-8')
        publisher.publish(PUBSUB_TOPIC_PATH, error_data_bytes, file_name=file_name.encode('utf-8'), status='error'.encode('utf-8'))
        raise # Re-raise the exception to indicate failure to Cloud Functions